insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:3-3-communication-in-business:learn:8edc2890', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Social Media & Websites", "reading": "<p><strong>Social media</strong> (Facebook, Instagram, Twitter/X, Pinterest): online platforms for sharing communication.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\">Huge number of users — massive reach for advertising</div>\n<div class=\"pro-item\">Information can be updated regularly</div>\n<div class=\"pro-item\">Visual images enhance communications</div>\n<div class=\"pro-item\">Cheaper than traditional media (TV, radio, print)</div>\n<div class=\"pro-item\">Allows customer feedback and interaction</div>\n<div class=\"pro-item\">Good for internal staff communication across locations</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\">Needs managing — updating and responding costs time and money</div>\n<div class=\"con-item\">Difficult to measure the effectiveness of campaigns</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Websites:</strong> operate 24/7; can take online orders; detailed product information; customers use search engines to find them; can be built and maintained cheaply. Risks: website crashing, spam, needs regular updating.</p>\n<p><strong>Targeting note:</strong> 90% of Instagram users are under 35 — good for reaching young audiences. Pinterest is popular with women and used for DIY, fashion, food.</p>", "question": "Which of the following is a genuine disadvantage of using social media for business communication?", "options": ["It cannot be used for internal staff communication", "It is difficult to measure the effectiveness of campaigns", "It has a very limited reach compared with traditional media", "It cannot be updated regularly"]}'::jsonb, '{"answer": 1, "explain": "The card lists difficulty measuring the effectiveness of campaigns as a disadvantage, while its advantages include huge reach, regular updating and internal staff use."}'::jsonb),
('business:3-3-communication-in-business:learn:dbce4368', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Importance of Communication in Each Functional Area", "reading": "<p><strong>Marketing:</strong> external communication for market research and advertising; internal communication for planning promotional campaigns</p>\n<p><strong>Finance:</strong> external communication to arrange bank loans; internal communication about income and expenditure to keep accurate accounts; digital tools have made invoicing, payments and financial reporting much faster (e.g. Quickbooks app)</p>\n<p><strong>Human Resources:</strong> external and internal communication for recruitment and selection; internal communication to resolve workplace problems, motivate workers, appraise performance</p>\n<p><strong>Operations / Production:</strong> internal communication about quality to reduce waste; marketing informs production about orders placed; external communication to enquire about raw material deliveries</p>\n<p><strong>Government and Trade:</strong> external communication to understand regulations; to apply for government grants</p>\n<p><strong>Choosing the right method:</strong> consider WHO you are communicating with, the PURPOSE of the communication, and what methods are AVAILABLE and AFFORDABLE. Internal vs external, size of audience, urgency, and sensitivity all affect the choice.</p>", "question": "According to the card, alongside who you are communicating with and what methods are available and affordable, what else should a business consider when choosing a communication method?", "options": ["The age of the business", "The total number of shareholders", "The colour scheme of the company logo", "The purpose of the communication"]}'::jsonb, '{"answer": 3, "explain": "The card states that a business should consider WHO it is communicating with, the PURPOSE of the communication, and what methods are AVAILABLE and AFFORDABLE."}'::jsonb),
('business:3-3-communication-in-business:learn:49433a8d', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "How Digital Communication Influences Business Activity", "reading": "<p><strong>Marketing:</strong> websites and social media allow businesses to reach millions globally; online selling has reduced the need for physical shops (e.g. Amazon, eBay); competition has increased as customers can compare prices more easily</p>\n<p><strong>Finance:</strong> invoices and payments sent more quickly; accounting information stored and processed digitally; financial reports prepared faster (Chatsworth Estate case study — one accountant handled 20× the business)</p>\n<p><strong>HR:</strong> jobs advertised on websites; applications and invitations by email; interviews by video-conferencing (Zoom/Teams); more staff working from home or while mobile; some jobs lost as productivity increased; workers required to retrain</p>\n<p><strong>Operations:</strong> production highly automated via robots; quality control improved (machines inspect and relay data); production is leaner — can be reprogrammed quickly in response to demand changes; GPS tracking of delivery drivers; staff monitoring via keyloggers, Microsoft Teams log-on records</p>\n<p><strong>Overall:</strong> digital communication has increased competition, enabled globalisation, reduced costs, and created new business opportunities (hardware makers, programmers, ICT trainers). Not all businesses have survived — some slow to adapt have closed (e.g. Blockbuster).</p>", "question": "What does the closure of businesses such as Blockbuster during the rise of digital communication demonstrate?", "options": ["Some businesses fail if they are too slow to adapt to digital change", "Only marketing departments are affected by digital communication", "Digital communication has no effect on business survival", "All traditional retailers are guaranteed to close eventually"]}'::jsonb, '{"answer": 0, "explain": "The card notes that not all businesses have survived the digital communication revolution — some, like Blockbuster, were too slow to adapt and closed."}'::jsonb),
('business:3-3-communication-in-business:misc:ac308a22', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Digital communication is always better than non-digital communication.</p><p><strong>✅ The correct idea:</strong> Digital communication is NOT always better. Face-to-face meetings allow immediate feedback, body language, and real-time discussion. They are better for sensitive issues (e.g. disciplinary matters, appraisals) and for building relationships. The OCR examiner regularly flags this as a FALSE statement in multiple-choice questions.</p>", "question": "Why might a face-to-face meeting be a better method than digital communication for a sensitive disciplinary matter?", "options": ["Meetings automatically create a permanent written record", "Meetings are always the cheapest communication method", "It gives immediate feedback and allows body language to be used", "Digital communication is always better regardless of the situation"]}'::jsonb, '{"answer": 2, "explain": "The correct concept is that digital communication is not always better — meetings allow immediate feedback and body language, making them more suitable for sensitive issues."}'::jsonb),
('business:3-3-communication-in-business:misc:f50afd7e', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All workers have benefited from the development of digital communication.</p><p><strong>✅ The correct idea:</strong> Digital communication has NOT benefited ALL workers. While many gained new opportunities, flexibility, and higher productivity, others lost their jobs as automation replaced them (e.g. shelf-label workers at Leclerc, DVD rental staff at Blockbuster). Some have had to undergo retraining to stay employed. Examiners specifically test this.</p>", "question": "Which statement correctly describes the overall impact of digital communication on workers?", "options": ["Only office-based workers have been affected by digital change", "All workers have benefited with no negative effects at all", "Some workers gained flexibility, others lost jobs to automation", "Digital communication has had no effect on employment"]}'::jsonb, '{"answer": 2, "explain": "The correct concept is that digital communication has NOT benefited all workers — some gained flexibility while others lost jobs to automation and had to retrain."}'::jsonb),
('business:3-3-communication-in-business:misc:4f6bd535', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Internal communication only goes downward — from managers to workers.</p><p><strong>✅ The correct idea:</strong> Internal communication can be VERTICAL (both upward AND downward) or HORIZONTAL. Upward communication goes from worker to manager. Horizontal communication goes between people at the same level (e.g. two department managers). Only treating communication as one-directional will cost marks.</p>", "question": "In which directions can internal communication travel within a business?", "options": ["Only horizontally, between people at the same level", "Only downward, from managers to workers", "Vertically (upward and downward) and horizontally", "Only upward, from workers to managers"]}'::jsonb, '{"answer": 2, "explain": "Internal communication can be vertical (upward or downward) or horizontal (between people at the same level), not just one-directional."}'::jsonb),
('business:3-3-communication-in-business:misc:9c9ea3f8', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Email is always the best method of communication for businesses.</p><p><strong>✅ The correct idea:</strong> The best method depends on the situation: who is being communicated with, the purpose, and what is available. For urgent issues needing immediate two-way discussion, a phone call may be better. For sensitive HR issues, face-to-face is preferred. For reaching thousands of customers, social media or a website may be best.</p>", "question": "What determines the best method of communication for a business to use in a given situation?", "options": ["Who is being communicated with, the purpose, and what is available", "Whichever method the sender personally prefers", "Email should always be used because it is the fastest method", "The cheapest method should always be chosen regardless of purpose"]}'::jsonb, '{"answer": 0, "explain": "The correct concept is that the best method depends on the situation — who is being contacted, the purpose, and what is available — not that one method (like email) is always best."}'::jsonb),
('business:3-3-communication-in-business:misc:2ea0f75c', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Social media is only useful for communicating with customers externally.</p><p><strong>✅ The correct idea:</strong> Social media can also be used for INTERNAL communications. Groups of workers can be linked through social media platforms to message each other, arrange meetings, share ideas, and receive instructions — especially useful for staff spread across multiple locations or working remotely.</p>", "question": "Besides communicating with customers, how else can a business use social media?", "options": ["As a tool for internal communication between workers across locations", "It cannot be used for any purpose other than customer communication", "Only for one-way announcements with no internal use", "It can only be used by businesses with a single location"]}'::jsonb, '{"answer": 0, "explain": "The correct concept is that social media can also be used for internal communication, linking workers across multiple locations or remote working."}'::jsonb),
('business:3-3-communication-in-business:misc:ebe21a15', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A meeting is always a disadvantage because it takes time and costs money.</p><p><strong>✅ The correct idea:</strong> Meetings have both advantages AND disadvantages. Advantages include immediate feedback, the ability to check understanding, discussion and idea generation, and the use of body language. Minutes provide a formal record. Online meetings (Teams, Zoom) reduce travel costs. Never say any method is purely good or bad — evaluation is always expected.</p>", "question": "What is the correct evaluative view of meetings as a communication method?", "options": ["Meetings should never be used to generate ideas or solve problems", "Meetings are always a disadvantage because they take time and cost money", "Meetings have no disadvantages when held online", "Meetings have both advantages, like feedback, and disadvantages, like cost"]}'::jsonb, '{"answer": 3, "explain": "The card stresses that meetings have both advantages (immediate feedback, discussion, minutes as a record) and disadvantages (time, cost) — no method should be judged as purely good or bad."}'::jsonb),
('business:3-3-communication-in-business:tips:9f785d5c', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse one advantage of a specific communication method (3 marks)", "reading": "Structure: (U) Identify a specific advantage of the METHOD — e.g. ''emails can be referred back to.'' (APP) Link to the specific business in the case study. (AN) Show the business-facing impact — e.g. ''this could improve customer service and reduce the risk of losing sales to competitors.'' CRITICAL: do NOT just describe what the method does — state the ADVANTAGE FOR THE BUSINESS.", "question": "In a 3-mark ''analyse one advantage of a communication method'' question, what is the critical error to avoid?", "options": ["Naming the specific method being used", "Explaining the business-facing impact of the advantage", "Linking the answer to the case study business", "Describing the method instead of stating its advantage"]}'::jsonb, '{"answer": 3, "explain": "The card warns that students must NOT just describe what the method does — they must state the actual advantage FOR THE BUSINESS to score analysis marks."}'::jsonb),
('business:3-3-communication-in-business:tips:39456cd2', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Recommend which method of communication to use (3 marks)", "reading": "Structure: (1 mark) Make a clear recommendation — ''SJ Salon should use a weekly email.'' (2 marks) Justify by comparing the two methods — your reason must explain why the chosen method is BETTER THAN the other. The justification must cover BOTH methods and be contextual (use case study detail). E.g. ''Three employees work part-time so finding a time when everyone can attend a meeting will be difficult — an email can be read at any time.''", "question": "In a 3-mark ''recommend which method of communication to use'' question, what must the justification for the remaining 2 marks include?", "options": ["Just a restatement of the method that was chosen", "A contextual comparison of why the chosen method is better", "A generic advantage with no reference to the case study", "A list of every possible communication method available"]}'::jsonb, '{"answer": 1, "explain": "The card requires the justification to compare BOTH methods, explaining why the chosen one is better than the other, using case study detail."}'::jsonb),
('business:3-3-communication-in-business:tips:20acd689', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse how digital communication has affected workers (6 marks)", "reading": "Two separate U→APP→AN chains, each worth 3 marks. Effect 1 (positive): e.g. working from home → more flexibility → better work-life balance → lower absenteeism. Effect 2 (negative): e.g. digital automation replaces jobs → workers made redundant → increased unemployment. Always show both sides for balance — the examiner rewards nuance.", "question": "For a 6-mark ''analyse how digital communication has affected workers'' question, what structure is expected?", "options": ["Two chains of impact, one positive and one negative", "Six short one-sentence points with no development", "One long chain covering six unrelated points", "A single paragraph focused only on positive effects"]}'::jsonb, '{"answer": 0, "explain": "The card explains the answer should have two separate U→APP→AN chains, each worth 3 marks, showing both a positive and a negative effect for balance."}'::jsonb),
('business:3-3-communication-in-business:tips:b9852582', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Calculation Warning — Percentage change calculations", "reading": "Formula: (New Value − Original Value) ÷ Original Value × 100. Example: £250,000 to £525,000 = (£525,000 − £250,000) ÷ £250,000 × 100 = 110%. The most common mistake is dividing by the NEW value instead of the ORIGINAL. If the value more than doubles, the answer MUST be over 100%.", "question": "When calculating percentage change, what is the most common mistake students make according to this tip?", "options": ["Rounding the original value before subtracting", "Adding the two values together instead of subtracting them", "Dividing by the new value instead of the original value", "Forgetting to multiply the result by 100"]}'::jsonb, '{"answer": 2, "explain": "The card warns that the formula requires dividing by the ORIGINAL value, and the most common mistake is dividing by the NEW value instead."}'::jsonb),
('business:3-3-communication-in-business:tips:83cc1208', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Explain Question (2 marks) — Explain one reason why communication is important for a business", "reading": "Structure: (K) Give a reason — e.g. ''Communication is important for marketing.'' (U) Explain why — e.g. ''so that customers know about what the business sells and can be persuaded to buy.'' The question does NOT require application to a specific business unless it says ''explain why THIS business...'' — read carefully.", "question": "For a 2-mark ''explain one reason why communication is important'' question, what does the mark scheme require?", "options": ["Only a definition of the word ''communication''", "Three separate developed points with case study detail", "A reason plus application to a named business in every case", "A reason (K) followed by an explanation of why it matters (U)"]}'::jsonb, '{"answer": 3, "explain": "The card gives the structure as (K) a reason followed by (U) an explanation of why, and notes application is only needed if the question specifically asks about a named business."}'::jsonb),
('business:3-3-communication-in-business:tips:86b59da0', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Examiner Warning — Always name the specific advantage — not just the method", "reading": "A very common error: writing ''email is a good method'' or ''meetings allow communication'' without stating WHAT the advantage is or WHY it helps the business. Examiners explicitly penalise vague responses. ''Quick and easy'' alone scores zero. State the specific feature: ''can be sent to multiple recipients at once'' or ''can be referred back to for clarification.''", "question": "Why would the answer ''email is a good method because it''s quick and easy'' score zero marks?", "options": ["It fails to state a specific advantage or explain how it helps", "It does not mention a named business from the case study", "Email is not accepted as a valid communication method by examiners", "The sentence is grammatically incorrect"]}'::jsonb, '{"answer": 0, "explain": "The card explains that vague responses like ''quick and easy'' are penalised because they do not state the specific feature or advantage for the business."}'::jsonb),
('business:3-3-communication-in-business:tips:74a54067', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Key Examiner Warning — Analysis must be business-facing", "reading": "Analysis marks are only awarded for impacts on the BUSINESS — such as effects on revenue, profit, market share, costs, customer service, employee retention, reputation, or productivity. Writing ''employees will feel more motivated'' scores as analysis. Writing ''better communication'' does NOT — it just restates the question. Always push to the business consequence.", "question": "According to the mark scheme, which type of statement counts as valid analysis in a communication question?", "options": ["A statement that just restates ''communication has improved''", "A statement showing a business-facing impact, e.g. motivation", "A statement about a competitor''s pricing strategy", "A statement describing how the method technically works"]}'::jsonb, '{"answer": 1, "explain": "The card states analysis marks require a business-facing impact — ''employees will feel more motivated'' scores as analysis, whereas ''better communication'' just restates the question and does not."}'::jsonb),
('business:3-3-communication-in-business:tips:8918bc0b', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Evaluation Tip — Evaluating the influence of digital communication", "reading": "For evaluate questions on digital communication, present BOTH benefits (lower costs, wider reach, globalisation, new products like Netflix) AND drawbacks (job losses, businesses that failed to adapt, workers needing retraining, increased competition). Conclude with a justified judgement — e.g. ''on balance, digital communication has been positive for most businesses because the cost savings and market reach outweigh the disruption.''", "question": "What must a strong evaluation answer on the influence of digital communication include?", "options": ["Both benefits and drawbacks, ending with a justified judgement", "A conclusion stating an opinion with no supporting reasons", "A list of communication methods with no conclusion", "Only the benefits, since digital communication is generally positive"]}'::jsonb, '{"answer": 0, "explain": "The card requires presenting BOTH benefits and drawbacks of digital communication, then concluding with a justified judgement, not a one-sided answer."}'::jsonb),
('business:3-3-communication-in-business:fib:f0f1b736', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 2, '{"question": "Communication is the _____ of a message from a sender to a receiver. When the receiver can reply, it is known as _____ communication.", "blankOptions": {"B1": ["productivity", "home", "website", "transmission"], "B2": ["social media", "two-way", "formal", "vertical"]}}'::jsonb, '{"blanks": {"B1": "transmission", "B2": "two-way"}}'::jsonb),
('business:3-3-communication-in-business:fib:0ef5b9c4', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 2, '{"question": "Digital communication is about sending and receiving information _____. It has transformed business activity. There is now greater _____ and trade has become more global.", "blankOptions": {"B1": ["costs", "productivity", "mobile", "electronically"], "B2": ["competition", "vertical", "website", "accounting"]}}'::jsonb, '{"blanks": {"B1": "electronically", "B2": "competition"}}'::jsonb),
('business:3-3-communication-in-business:fib:a9199f43', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 2, '{"question": "The _____ of workers has been increased by digital communication and production _____ have fallen as a result.", "blankOptions": {"B1": ["mobile", "website", "productivity", "retraining"], "B2": ["home", "horizontal", "website", "costs"]}}'::jsonb, '{"blanks": {"B1": "productivity", "B2": "costs"}}'::jsonb),
('business:3-3-communication-in-business:fib:d94e2dc8', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 2, '{"question": "Finance departments can store and process _____ information more quickly. Marketing departments use websites and _____ to reach potentially huge markets.", "blankOptions": {"B1": ["website", "accounting", "competition", "horizontal"], "B2": ["horizontal", "social media", "retraining", "costs"]}}'::jsonb, '{"blanks": {"B1": "accounting", "B2": "social media"}}'::jsonb),
('business:3-3-communication-in-business:fib:37db8576', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 3, '{"question": "Human resource departments have seen more staff working while _____ or working from _____. Some workers have lost their jobs or had to undergo _____.", "blankOptions": {"B1": ["feedback", "vertical", "accounting", "mobile"], "B2": ["two-way", "horizontal", "home", "productivity"], "B3": ["one-way", "retraining", "website", "formal"]}}'::jsonb, '{"blanks": {"B1": "mobile", "B2": "home", "B3": "retraining"}}'::jsonb),
('business:3-3-communication-in-business:fib:4a93a461', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 2, '{"question": "A _____ is an online location that links pages of information. It allows sales to be made online and operates _____.", "blankOptions": {"B1": ["retraining", "accounting", "transmission", "website"], "B2": ["24/7", "transmission", "mobile", "accounting"]}}'::jsonb, '{"blanks": {"B1": "website", "B2": "24/7"}}'::jsonb),
('business:3-3-communication-in-business:match:b6f848c5', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Communication”?", "options": ["Communication where the receiver can reply to the sender, allowing feedback and discussion", "Communication between people on different layers of the organisational hierarchy — either upward or downward", "Communication between people at the same level within the organisation structure", "The transmission of a message from a sender to a receiver through a means of communication"]}'::jsonb, '{"answer": 3, "explain": "“Communication” means: The transmission of a message from a sender to a receiver through a means of communication"}'::jsonb),
('business:3-3-communication-in-business:match:66bc7a56', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Two-way communication”?", "options": ["Communication between people on different layers of the organisational hierarchy — either upward or downward", "Communication between people at the same level within the organisation structure", "Communication that uses the official channels of an organisation, such as letters, official meetings, and reports", "Communication where the receiver can reply to the sender, allowing feedback and discussion"]}'::jsonb, '{"answer": 3, "explain": "“Two-way communication” means: Communication where the receiver can reply to the sender, allowing feedback and discussion"}'::jsonb),
('business:3-3-communication-in-business:match:53b8b7f1', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Vertical communication”?", "options": ["Communication between people at the same level within the organisation structure", "Communication between people on different layers of the organisational hierarchy — either upward or downward", "Communication that uses the official channels of an organisation, such as letters, official meetings, and reports", "The electronic exchange of information using ICT — including voice, text, images and video"]}'::jsonb, '{"answer": 1, "explain": "“Vertical communication” means: Communication between people on different layers of the organisational hierarchy — either upward or downward"}'::jsonb),
('business:3-3-communication-in-business:match:ba2df6c5', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Horizontal communication”?", "options": ["Communication that uses the official channels of an organisation, such as letters, official meetings, and reports", "Communication between people at the same level within the organisation structure", "The electronic exchange of information using ICT — including voice, text, images and video", "Online applications that allow people to create and share content to participate in social networking"]}'::jsonb, '{"answer": 1, "explain": "“Horizontal communication” means: Communication between people at the same level within the organisation structure"}'::jsonb),
('business:3-3-communication-in-business:match:9bc3adbc', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Formal communication”?", "options": ["Communication that uses the official channels of an organisation, such as letters, official meetings, and reports", "The electronic exchange of information using ICT — including voice, text, images and video", "Online applications that allow people to create and share content to participate in social networking", "The response made by the receiver of a communication indicating whether they have understood the message"]}'::jsonb, '{"answer": 0, "explain": "“Formal communication” means: Communication that uses the official channels of an organisation, such as letters, official meetings, and reports"}'::jsonb),
('business:3-3-communication-in-business:match:e6ba3f5e', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Digital communication”?", "options": ["Online applications that allow people to create and share content to participate in social networking", "The electronic exchange of information using ICT — including voice, text, images and video", "The response made by the receiver of a communication indicating whether they have understood the message", "The transmission of a message from a sender to a receiver through a means of communication"]}'::jsonb, '{"answer": 1, "explain": "“Digital communication” means: The electronic exchange of information using ICT — including voice, text, images and video"}'::jsonb),
('business:3-3-communication-in-business:match:b826cca0', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Social media”?", "options": ["Online applications that allow people to create and share content to participate in social networking", "The response made by the receiver of a communication indicating whether they have understood the message", "The transmission of a message from a sender to a receiver through a means of communication", "Communication where the receiver can reply to the sender, allowing feedback and discussion"]}'::jsonb, '{"answer": 0, "explain": "“Social media” means: Online applications that allow people to create and share content to participate in social networking"}'::jsonb),
('business:3-3-communication-in-business:match:bec4475e', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Feedback”?", "options": ["The transmission of a message from a sender to a receiver through a means of communication", "Communication where the receiver can reply to the sender, allowing feedback and discussion", "The response made by the receiver of a communication indicating whether they have understood the message", "Communication between people on different layers of the organisational hierarchy — either upward or downward"]}'::jsonb, '{"answer": 2, "explain": "“Feedback” means: The response made by the receiver of a communication indicating whether they have understood the message"}'::jsonb),
('business:3-4-recruitment-and-selection:exam:4d1175c0', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'exam', 'mcq', 1, '{"num": "QUESTION 01", "question": "What would be included in the job description for a hospital doctor?", "options": ["A list of the medical qualifications required", "An ability to listen carefully to patients'' concerns", "Previous experience of working in a hospital", "The main duties of medical staff when working in a hospital"], "hint": "A job description is about the TASKS and DUTIES of the job — not about the personal attributes or qualifications of the person doing it.", "starter": "A job description includes..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p>Answer: <strong>D — The main duties of medical staff when working in a hospital.</strong></p><p>A job description lists the duties, tasks and responsibilities of the role. Qualifications (A), personal qualities (B) and experience (C) all belong in the person specification.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:d4f9a09f', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of external recruitment?", "options": ["Promoting a worker from another department", "Emailing staff about a vacancy", "Advertising in a national newspaper", "Putting a notice on the company intranet"]}'::jsonb, '{"answer": 2, "explain": "External recruitment means filling a vacancy with someone from outside the organisation. Advertising in a national newspaper is an external method. The other options are all internal methods."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:4bb34fd5', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "A job description includes which of the following?", "options": ["The qualifications required by the applicant", "The personal qualities the worker must have", "The main duties and responsibilities of the worker", "The experience needed to perform the job"]}'::jsonb, '{"answer": 2, "explain": "A job description lists the duties, tasks and responsibilities of the worker. Qualifications, personal qualities and experience needed belong in the person specification."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:f6784020', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which item belongs in a person specification?", "options": ["The hours of work", "The main tasks of the job", "The skills and qualifications needed", "The name of the line manager"]}'::jsonb, '{"answer": 2, "explain": "A person specification lists the qualities, qualifications and knowledge a person should have. Tasks, line manager details and hours of work belong in the job description."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:b969f20d', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Danielle advertises on Indeed at 60p per click. 350 people click on the advert and she contacts 16 applicants at £1 each. What is the total cost?", "options": ["£226", "£262", "£622", "£227"]}'::jsonb, '{"answer": 1, "explain": "350 × £0.60 = £210. 16 × £1 = £16. Total = £210 + £16 = £226. Answer: A. (Note: the original OCR answer is A = £226.)"}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:0e524d80', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following would be used to shortlist candidates?", "options": ["Reference", "Letter of application", "Interview", "Group activity"]}'::jsonb, '{"answer": 1, "explain": "Letters of application (along with CVs and application forms) are used to create a shortlist. Interviews, group activities and references are used at the final selection stage."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:f420f545', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following is an advantage for a business of using a CV rather than an application form?", "options": ["It ensures all applicants provide the same information", "It shows an applicant''s ability to organise relevant information", "It is easier for the business to compare applicants", "Applicants are less likely to leave out essential information"]}'::jsonb, '{"answer": 1, "explain": "A CV shows the applicant''s ability to organise information. Application forms are actually better for ensuring all applicants provide the same specific information and for making comparisons."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:a9eb3671', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "A business has a skills gap. Which action would best solve this?", "options": ["Ask existing employees to work fewer hours", "Advertise internally on the company noticeboard", "Reduce the number of employees", "Recruit an external specialist with the required skills"]}'::jsonb, '{"answer": 3, "explain": "A skills gap means the business lacks workers with specific skills. The solution is to recruit externally — specifically seeking someone with those skills from outside the business."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:8b8a6f4a', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of internal recruitment?", "options": ["It is more expensive than external recruitment", "Workers need more induction training", "Existing staff may not bring fresh ideas", "It takes longer than external recruitment"]}'::jsonb, '{"answer": 2, "explain": "A key disadvantage of internal recruitment is that existing staff may not add new ideas to help the business improve. Internal recruitment is actually cheaper and faster than external."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:381d291a', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Waitrose uses interviews, group activities and tests in its selection process. Which method is best for assessing how well a candidate works in a team?", "options": ["Group activity", "Test", "CV", "Interview"]}'::jsonb, '{"answer": 0, "explain": "Group activities reveal how well people work with others — their interpersonal skills. Interviews assess communication and presentation; tests assess specific technical skills."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:17576740', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following is a method of internal recruitment?", "options": ["Posting on the company website for staff", "Advertising in a specialist magazine", "Using a recruitment agency", "Advertising in a local newspaper"]}'::jsonb, '{"answer": 0, "explain": "The company website can be used internally (to notify existing staff) as well as externally. Local newspapers, recruitment agencies and specialist magazines are all external methods."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:210f6c2c', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "A job description lists the qualifications and skills needed for the job."}'::jsonb, '{"answer": false, "explain": "False. A job description lists the duties, tasks and responsibilities of the role. Qualifications and skills belong in the person specification."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:6c44bb8e', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "Internal recruitment is always cheaper and quicker than external recruitment."}'::jsonb, '{"answer": true, "explain": "True. Internal recruitment saves advertising costs and the person can start sooner as they don''t need to give notice elsewhere."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:03264ec0', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "A CV makes it easy for the business to compare applicants because all applicants provide the same information."}'::jsonb, '{"answer": false, "explain": "False. An application form ensures all applicants provide the same information in the same format, making comparison easier. A CV is structured by the applicant."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:d9a61ce8', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "One disadvantage of internal recruitment is that existing staff may not bring fresh ideas to the business."}'::jsonb, '{"answer": true, "explain": "True. This is a key disadvantage of internal recruitment. Fresh ideas and new skills are more likely to come from external candidates."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:9c0138a4', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "References are always a reliable source of information about a candidate."}'::jsonb, '{"answer": false, "explain": "False. Businesses sometimes give workers good references because they want them to leave. This is why organisations often use more than one method of selection."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:9d780d46', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "Group activities are best for assessing a candidate''s ability to work as part of a team."}'::jsonb, '{"answer": true, "explain": "True. Group activities reveal interpersonal skills and how well people work with others — something that is difficult to assess through interviews or tests alone."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:f4dd20ec', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "External recruitment methods include notice boards, word of mouth and emails to staff."}'::jsonb, '{"answer": false, "explain": "False. These are internal recruitment methods. External methods include websites, local/national newspapers, specialist magazines, social media and job centres."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:3745576c', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "A skills gap occurs when a business needs workers with specialist skills it does not currently have."}'::jsonb, '{"answer": true, "explain": "True. A skills gap often arises when new production methods or technologies are introduced, requiring the business to recruit externally for those skills."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:e4a66b9a', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "Interviews are sufficient on their own to make a fully informed recruitment decision."}'::jsonb, '{"answer": false, "explain": "False. Interviews can give the wrong impression, and sometimes applicants are not entirely honest. Organisations often use more than one method of selection to build an accurate picture."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:2c8b4d15', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "Induction training is needed for both internal and external recruits."}'::jsonb, '{"answer": false, "explain": "False. Induction training is mainly needed for external recruits. An internal recruit already knows the organisation, its aims, and how things work — so induction training may not be needed, saving the business money."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:ede31e95', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Core Terminology", "reading": "<ul>\n<li><strong>Recruitment</strong> — The process of finding people to work in a new or established business</li>\n<li><strong>Selection</strong> — The process of choosing between applicants for a job</li>\n<li><strong>Internal recruitment</strong> — When a job vacancy is filled by employing someone who is already an employee of the business. Methods include notice boards, word of mouth, company website and emails to staff</li>\n<li><strong>External recruitment</strong> — When a job vacancy is filled by employing someone from outside the business. Methods include websites, newspaper, social media and specialist magazines</li>\n<li><strong>Skills gap</strong> — When a business recruits skilled workers because it is short of them</li>\n<li><strong>Job description</strong> — A list of the main duties, tasks and responsibilities of a worker</li>\n<li><strong>Person specification</strong> — A list of the qualities, qualifications and knowledge that a person should have to do a particular job</li>\n<li><strong>Induction training</strong> — Training to introduce a new worker to the business, place of work and their fellow workers as well as their job</li>\n<li><strong>Recruitment agency</strong> — A specialist agency that carries out all the tasks involved in recruitment and selection of workers on behalf of an organisation</li>\n<li><strong>Employment agency</strong> — An agency that has workers readily available for business hire, usually for a short period of time</li>\n<li><strong>CV (curriculum vitae)</strong> — A document on which the applicant outlines their personal details, experience and skills</li>\n<li><strong>Application form</strong> — A form which asks applicants for personal details, experience and skills</li>\n<li><strong>Letter of application</strong> — A letter written by the applicant usually explaining why they think they are suitable for the job</li>\n</ul>", "question": "According to core recruitment terminology, what is ''selection''?", "options": ["A list of duties and responsibilities of a worker", "The process of finding people to work in a business", "The process of choosing between applicants for a job", "Training a new worker to fit into the business"]}'::jsonb, '{"answer": 2, "explain": "Selection is defined as the process of choosing between applicants for a job, distinct from recruitment (finding people to work in the business)."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:afd568e8', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Why Businesses Recruit", "reading": "<p>There are three main reasons why businesses recruit new workers:</p>\n<ul>\n<li><strong>Starting up or growing</strong> — A new business must recruit workers from scratch. A business getting increased orders or making more sales may increase production and need more workers</li>\n<li><strong>To replace staff who leave</strong> — Staff leave for all kinds of reasons: promotion, retirement, to do something different, or because they have been dismissed</li>\n<li><strong>Skills shortage / Skills gap</strong> — May arise as new methods of production are introduced, perhaps using new technology. Recruiting skilled workers can be very difficult, particularly if the economy is doing well. It is not unusual for businesses to look abroad when recruiting skilled workers</li>\n</ul>\n<p><strong>Note from OCR delivery guide:</strong> Sometimes the work can be reallocated amongst other posts to avoid the need to replace the job role. Businesses should not automatically recruit whenever someone leaves.</p>\n<p><strong>Cost of poor recruitment:</strong> Oxford Economics research found replacing a staff member costs on average £30,614. Lost output during the settling-in period (28 weeks on average) accounts for £25,181, with direct recruitment costs of £5,433 covering agency fees, advertising, management time and HR processing.</p>", "question": "According to the OCR delivery guide note, what should a business consider before recruiting a replacement for a worker who has left?", "options": ["Whether to increase the salary of the role", "Whether to promote the departing worker''s manager", "Whether the work could be reallocated instead", "Whether to close the department entirely"]}'::jsonb, '{"answer": 2, "explain": "The card notes work can sometimes be reallocated among other posts, and businesses should not automatically recruit whenever someone leaves."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:3a9e4ef6', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "The Recruitment & Selection Process", "reading": "<p>The recruitment and selection process has two main stages:</p>\n<p><strong>Recruitment stage:</strong></p>\n<ul>\n<li>Step 1: Identify a vacancy</li>\n<li>Step 2: Write a job description</li>\n<li>Step 3: Write a person specification</li>\n<li>Step 4: Advertise the vacancy</li>\n<li>Step 5: Receive applications</li>\n</ul>\n<p><strong>Selection stage:</strong></p>\n<ul>\n<li>Step 6: Shortlist candidates (using CVs, application forms, letters of application)</li>\n<li>Step 7: Carry out interviews / tests / group activities</li>\n<li>Step 8: Make a job offer</li>\n</ul>\n<p><strong>Important distinction:</strong> ''Recruitment'' refers to searching for suitable candidates and attracting them to apply. ''Selection'' refers to vetting candidates to choose the most suitable one.</p>", "question": "Which of the following best describes ''selection'' in the recruitment and selection process?", "options": ["Writing the job description and person specification", "Searching for and attracting suitable candidates to apply", "Advertising the vacancy to attract applicants", "Vetting candidates to choose the most suitable one"]}'::jsonb, '{"answer": 3, "explain": "The card states selection refers to vetting candidates to choose the most suitable person, while recruitment means searching for and attracting candidates."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:ca7f50b2', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Job Description vs Person Specification", "reading": "<p><strong>Job Description</strong> — lists the tasks and responsibilities the worker must perform. It helps the business be clear about what work it wants done, and helps applicants decide if they want to apply.</p>\n<p>A job description typically includes: job title, grade/pay scale, who the person is responsible to, job purpose, and main duties/tasks.</p>\n<p><strong>Person Specification</strong> — states the knowledge, qualifications, experience, personal qualities and skills the worker will need. It helps the business decide what kind of person to appoint and which selection methods to use.</p>\n<p>A person specification typically includes: qualifications (essential/desirable), experience, knowledge/skills/abilities, and special requirements (e.g. driving licence). Each attribute is marked E (essential) or D (desirable) and the method of assessment is noted (AF = application form, I = interview, R = reference, T = test).</p>\n<div class=\"two-col\" style=\"margin-top:10px;\">\n<div>\n<div class=\"col-head\">Job Description Contains</div>\n<div class=\"pro-item\">Job title and department</div>\n<div class=\"pro-item\">Hours of work and location</div>\n<div class=\"pro-item\">Main duties and tasks</div>\n<div class=\"pro-item\">Who the worker reports to</div>\n</div>\n<div>\n<div class=\"col-head\">Person Specification Contains</div>\n<div class=\"pro-item\">Qualifications required</div>\n<div class=\"pro-item\">Experience needed</div>\n<div class=\"pro-item\">Skills and personal qualities</div>\n<div class=\"pro-item\">Special requirements (e.g. can drive)</div>\n</div>\n</div>", "question": "In a person specification, what does marking an attribute as ''D'' indicate?", "options": ["The candidate must demonstrate it at interview", "The attribute disqualifies the candidate", "The attribute is desirable but not essential", "The attribute is required by law"]}'::jsonb, '{"answer": 2, "explain": "The card explains each attribute in a person specification is marked E (essential) or D (desirable)."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:15e91aa5', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Internal vs External Recruitment", "reading": "<p><strong>Internal recruitment</strong> — filling a vacancy with someone who already works in the organisation.</p>\n<p>Internal advertising methods: noticeboard, word of mouth/staff meetings, company (in-house) magazine, the firm''s website, social media used by workers, emails to workers.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Internal Advantages</div>\n<div class=\"pro-item\">Cheaper to advertise internally</div>\n<div class=\"pro-item\">Quicker — no need to give notice externally</div>\n<div class=\"pro-item\">Person already knows the organisation — less induction training needed</div>\n<div class=\"pro-item\">Organisation already knows the candidate — less risk</div>\n<div class=\"pro-item\">Motivates existing workforce — promotion opportunities</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Internal Disadvantages</div>\n<div class=\"con-item\">Existing staff may not bring new ideas</div>\n<div class=\"con-item\">Limited choice of applicants</div>\n<div class=\"con-item\">Other workers may become jealous — conflict</div>\n<div class=\"con-item\">The job vacated by the person promoted still needs to be filled</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>External recruitment</strong> — filling a vacancy with someone from outside the organisation. Used when: starting up, skills gap exists, new ideas needed, more workers needed, or promoting internally would cause conflict.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ External Advantages</div>\n<div class=\"pro-item\">Wider range of skills and experience</div>\n<div class=\"pro-item\">Fresh ideas from outside the business</div>\n<div class=\"pro-item\">More applicants to choose from</div>\n<div class=\"pro-item\">No need to backfill the promoted person''s role</div>\n</div>\n<div>\n<div class=\"col-head\">✗ External Disadvantages</div>\n<div class=\"con-item\">More expensive (advertising, agency fees)</div>\n<div class=\"con-item\">Takes longer to recruit</div>\n<div class=\"con-item\">Induction training needed — higher cost</div>\n<div class=\"con-item\">Greater risk — managers don''t know the candidate well</div>\n</div>\n</div>", "question": "Which of these is a disadvantage of internal recruitment, according to the card?", "options": ["It requires more induction training", "It takes longer than external recruitment", "Their old role still needs to be filled by someone", "It brings a wider range of skills and experience"]}'::jsonb, '{"answer": 2, "explain": "The card lists that the job vacated by the promoted person still needs to be filled as a disadvantage of internal recruitment; the other options actually describe external recruitment or its disadvantages."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:c7881121', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Advertising Media", "reading": "<p>When advertising a job, a business considers: whether to recruit internally or externally; the type of worker required; how many workers are needed; the location; and the budget available.</p>\n<ul>\n<li><strong>Websites (e.g. Indeed, Reed, Monster)</strong> — Used for all types of jobs, local and national. Applicants can search by type, salary and location. Businesses can search posted CVs. Both internal and external.</li>\n<li><strong>Social media</strong> — Increasingly used for many kinds of jobs because of wide reach. Useful for finding graduates and younger applicants. Both internal and external.</li>\n<li><strong>Local newspapers</strong> — Useful when looking for local workers only (hairdressers, carers, retail). Not usually expensive. External.</li>\n<li><strong>National newspapers</strong> — Used when recruiting skilled workers and there may be a shortage locally. More expensive. External.</li>\n<li><strong>Specialist magazines</strong> — e.g. Times Educational Supplement (teachers), The Lancet (doctors). Used to recruit highly skilled workers such as consultants, engineers, scientists. External.</li>\n<li><strong>Job centres</strong> — Government-run; free to use; useful for people without internet access. External.</li>\n<li><strong>Word of mouth</strong> — Business lets existing employees know about a vacancy. Saves advertising cost. Both internal and external.</li>\n<li><strong>Email/noticeboard/company magazine</strong> — Internal methods only.</li>\n</ul>", "question": "According to the card, what are specialist magazines (e.g. Times Educational Supplement) mainly used to recruit?", "options": ["Highly skilled workers like consultants", "Internal staff seeking promotion", "Workers for short-term temporary contracts", "Local unskilled retail staff"]}'::jsonb, '{"answer": 0, "explain": "The card states specialist magazines are used to recruit highly skilled workers such as consultants, engineers and scientists."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:320c18cf', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Methods of Selection", "reading": "<p>Selection is divided into two stages: shortlisting, then the final selection stage.</p>\n<p><strong>Shortlisting methods</strong> (used to draw up a list of candidates to interview):</p>\n<ul>\n<li><strong>Letter of application</strong> — Written by the applicant explaining why they are suitable. Good for showing communication skills, use of punctuation and grammar, and experience. Applicant puts themselves in the best light.</li>\n<li><strong>CV (curriculum vitae)</strong> — Summary of personal details, qualifications, employment history and referees. Shows ability to organise information. Easy to see essential details at a glance.</li>\n<li><strong>Application form</strong> — Business specifies what information it needs; all applicants fill in the same form. Easy to compare applicants. Less likely to miss essential information than a CV.</li>\n</ul>\n<p><strong>Final selection methods:</strong></p>\n<ul>\n<li><strong>Interviews</strong> — Employer sees candidates face-to-face and can judge how well they present themselves, communicate and are likely to fit in. Often the same questions are asked of all candidates. Good for assessing personality, communication skills and reaction under pressure.</li>\n<li><strong>Tests and presentations</strong> — Check specific skills (e.g. typing, IT, maths). Presentations show how well a candidate can communicate ideas. Gives very specific, measurable information.</li>\n<li><strong>Group activities</strong> — Applicants work together on a task. Reveals interpersonal/teamworking skills and leadership ability. Particularly useful when the job requires working closely with others.</li>\n<li><strong>References</strong> — Statement from a previous employer about work done, how well they did their job, punctuality and attendance. Can verify information from the CV/application form. Provides a third-party view, though references can sometimes be misleading.</li>\n</ul>", "question": "Which method is used at the shortlisting stage rather than the final selection stage?", "options": ["Interview", "Reference", "Application form", "Group activity"]}'::jsonb, '{"answer": 2, "explain": "The card places letters of application, CVs and application forms at the shortlisting stage, while interviews, tests, group activities and references belong to final selection."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:8f92a014', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Recruitment & Employment Agencies", "reading": "<p><strong>Recruitment agencies</strong> do the work of recruiting and selecting staff on behalf of businesses. The agency:</p>\n<ul>\n<li>Draws up a job description and person specification (in consultation with the firm)</li>\n<li>Advertises for applications</li>\n<li>Recommends a shortlist of suitable people</li>\n<li>The firm then interviews recommended candidates before making a final decision</li>\n</ul>\n<p>Using a recruitment agency saves time and money if it reduces the need for a large HR department. The agency is a specialist organisation that knows how and where to advertise and what information is needed about applicants.</p>\n<p><strong>Employment agencies</strong> keep lists of people willing to do certain kinds of work (e.g. receptionists, office typists). A firm can ask for a worker for a short period of time, paying the worker''s wage plus the agency''s fee. If the temporary worker performs well, the firm may offer a permanent post — though the agency may charge a further introduction fee.</p>", "question": "What is the key difference between a recruitment agency and an employment agency, according to the card?", "options": ["Recruitment agencies only advertise vacancies, while employment agencies conduct interviews", "Employment agencies are free to use, while recruitment agencies always charge a fee", "Employment agencies supply short-term hires; recruitment agencies handle full recruitment", "Recruitment agencies are used only by small businesses"]}'::jsonb, '{"answer": 2, "explain": "The card explains recruitment agencies carry out the recruitment/selection process for a business, while employment agencies keep lists of workers available for short-term hire."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:78ff8c80', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Recruitment'' and ''selection'' mean the same thing.</p><p><strong>✅ The correct idea:</strong> They are different stages. Recruitment refers to searching for suitable candidates and attracting them to apply for a vacancy. Selection refers to the process of vetting candidates to choose the most suitable person for the role.</p>", "question": "What is the correct distinction between ''recruitment'' and ''selection''?", "options": ["Selection means advertising a vacancy", "Recruitment happens after selection is complete", "Recruitment and selection are two words for the same process", "Recruitment attracts candidates; selection vets the best one"]}'::jsonb, '{"answer": 3, "explain": "The card clarifies recruitment and selection are different stages: recruitment attracts candidates, selection vets them to choose the best person."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:eb3bf49e', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A job description lists the qualifications and skills needed for the job.</p><p><strong>✅ The correct idea:</strong> A job description lists the tasks, duties and responsibilities of the role. Qualifications and skills needed belong in the person specification. Confusing these two documents is one of the most common errors in GCSE exams.</p>", "question": "What does a job description actually list?", "options": ["The tasks, duties and responsibilities of the role", "The salary and benefits package", "The personal qualities of an ideal candidate", "The qualifications and skills needed for the job"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the common misconception that a job description lists qualifications/skills — that belongs in the person specification; a job description lists tasks, duties and responsibilities."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:e9c01ac2', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Internal recruitment is always better because it is cheaper.</p><p><strong>✅ The correct idea:</strong> Internal recruitment has advantages (cheaper, quicker, motivated staff) but also disadvantages (no fresh ideas, limited choice, causes conflict). The best method depends on the specific situation — for example, if a business needs a skills gap filled, external recruitment is needed.</p>", "question": "Why is it wrong to say internal recruitment is ''always better'' than external recruitment?", "options": ["The best method depends on the situation faced", "Because internal recruitment always causes conflict among staff", "Because internal recruitment is always more expensive", "Because external recruitment is always quicker"]}'::jsonb, '{"answer": 0, "explain": "The card explains internal recruitment has both advantages and disadvantages, and the best method depends on the situation — e.g. filling a skills gap needs external recruitment."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:71b17005', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When an employee leaves, a business must always recruit a replacement.</p><p><strong>✅ The correct idea:</strong> Not necessarily. Sometimes the work can be redistributed to other employees. Businesses should analyse their HR needs before automatically recruiting. Recruitment is expensive and time-consuming, so the need must be justified.</p>", "question": "Is it true that a business must always recruit a replacement when an employee leaves?", "options": ["No — the role is simply removed from the organisation permanently", "No — the work can sometimes go to other employees", "Yes — a business must recruit within one week by law", "Yes — otherwise the person specification becomes invalid"]}'::jsonb, '{"answer": 1, "explain": "The card corrects this misconception, explaining that work can sometimes be redistributed to other employees, and the need to recruit must be justified since it is expensive and time-consuming."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:2c74f014', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A CV is better than an application form because the applicant includes all the information.</p><p><strong>✅ The correct idea:</strong> A CV shows the applicant''s ability to organise information, but applicants may leave out essential details. Application forms ensure all applicants provide exactly the same information, making it easier to compare them. Each method has its advantages.</p>", "question": "Why might an application form be considered better than a CV for comparing applicants?", "options": ["It is cheaper to produce than a CV", "It ensures every applicant gives the same information", "It always includes more personal details than a CV", "It guarantees the applicant is telling the truth"]}'::jsonb, '{"answer": 1, "explain": "The card explains application forms ensure all applicants provide identical information, making comparison easier, whereas a CV''s structure is decided by the applicant and may omit details."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:002555ca', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> References always provide accurate, honest information about a candidate.</p><p><strong>✅ The correct idea:</strong> References can be misleading. Sometimes employers give workers good references because they want them to leave. For this reason, businesses often use more than one method of selection to build a fuller picture of each candidate.</p>", "question": "Why can references sometimes be misleading?", "options": ["Employers may give good references to workers they want gone", "References replace the need for an interview", "References are only used for internal recruitment", "References are always written by the candidate themselves"]}'::jsonb, '{"answer": 0, "explain": "The card notes that employers sometimes give good references because they want a worker to leave, which is why businesses use more than one selection method."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:dc5f8eb5', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Some learners refer to the ''person specification'' as the ''job specification''.</p><p><strong>✅ The correct idea:</strong> The correct term used in the OCR specification is ''person specification''. Always use this term in your answers to show precise subject knowledge.</p>", "question": "Which term is the correct OCR specification term for the document listing a candidate''s required qualities and qualifications?", "options": ["Person specification", "Role specification", "Job specification", "Candidate description"]}'::jsonb, '{"answer": 0, "explain": "The card states the correct OCR term is ''person specification'', not ''job specification''."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:d67b20f6', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Question Type — 2-mark Explain questions (AO1b + AO2)", "reading": "<p>You need <strong>Knowledge (1 mark)</strong> + <strong>Application (1 mark)</strong>.</p>\n<p>State the advantage/disadvantage, then link it specifically to the business in the question.</p>\n<p><em>Example: \"External recruitment may bring new ideas (K) which is important for Waitrose as it operates in a very competitive supermarket industry where new product development is key (APP).\"</em></p>", "question": "What two marks make up a 2-mark ''Explain'' question (AO1b + AO2)?", "options": ["Knowledge (1 mark) + Application (1 mark)", "Application (1 mark) + Analysis (1 mark)", "Knowledge (1 mark) + Evaluation (1 mark)", "Understanding (1 mark) + Evaluation (1 mark)"]}'::jsonb, '{"answer": 0, "explain": "The card states 2-mark Explain questions require Knowledge (1 mark) plus Application (1 mark), linking the point specifically to the business in the question."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:9a65affe', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Question Type — 3-mark Analyse questions (AO1b + AO2 + AO3a)", "reading": "<p>State the advantage/method → Apply to the business → Analyse the business impact.</p>\n<p><em>Example: \"Interviews allow the interviewer to ask detailed questions about the candidates'' skills (K). Given that Clarks designers work with fast-changing fashion trends (APP), this will allow Clarks to select workers who are up-to-date, potentially increasing market share (AN).\"</em></p>", "question": "What is the correct structure for a 3-mark ''Analyse'' question?", "options": ["State the advantage, then make a final judgement", "State the method, apply it, then analyse the impact", "State two separate advantages of the method", "Describe the method, then compare it to an alternative"]}'::jsonb, '{"answer": 1, "explain": "The card explains 3-mark Analyse questions require: state the advantage/method, apply it to the business, then analyse the business impact (K+APP+AN)."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:8636ca01', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Question Type — 3-mark Recommend questions (AO3b)", "reading": "<p>You must: (1) Make a clear decision — don''t sit on the fence. (2) Justify why your chosen method is better than the alternative — a comparison is essential. (3) Use context from the case study.</p>\n<p><em>Example: \"Interviews are likely to be more effective (1) because Clarks can assess candidates'' knowledge of current fashion (CONT). A reference is unlikely to include this information unless they previously worked for another fashion business (+2).\"</em></p>", "question": "What must a student do to access full marks on a 3-mark ''Recommend'' question (AO3b)?", "options": ["Make a decision, justified against the alternative", "Describe both methods without making a decision", "List as many advantages as possible without choosing one option", "Simply repeat the question in the answer"]}'::jsonb, '{"answer": 0, "explain": "The card states students must make a clear decision, justify why the chosen method is better than the alternative (a comparison is essential), and use case study context."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:3af74f32', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Question Type — 9-mark Evaluate questions (AO1a + AO1b + AO2 + AO3a + AO3b)", "reading": "<p>Use the marking grid: Knowledge (1) → Understanding (1) → Application/data (2) → Analysis (2) → Evaluation (3).</p>\n<ul>\n<li>Use data from the case study to earn application marks (e.g. calculate differences in costs)</li>\n<li>Give both advantages and disadvantages of the recruitment method</li>\n<li>Make a final judgement that is contextually justified using information from the case study</li>\n</ul>", "question": "According to the marking grid for a 9-mark Evaluate question, how many marks are allocated to Evaluation?", "options": ["3 marks", "1 mark", "4 marks", "2 marks"]}'::jsonb, '{"answer": 0, "explain": "The card''s marking grid allocates Knowledge (1) + Understanding (1) + Application/data (2) + Analysis (2) + Evaluation (3) = 9 marks."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:798c922f', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Common Error — Don''t just describe the method — give the advantage", "reading": "<p>Examiners do NOT award marks for describing what a method is (e.g. \"an interview is where you ask candidates questions\"). You must state the <strong>advantage for the business</strong> of using that method.</p>\n<p>Also avoid generic phrases like \"it helps find the best person for the job\" — this is the purpose of all selection methods and earns no marks.</p>", "question": "Why do examiners award no marks for a statement like ''an interview is where you ask candidates questions''?", "options": ["It just describes the method, not a business advantage", "Because interviews are not a valid selection method", "Because it should be written in the case study instead", "Because it exceeds the word limit for the question"]}'::jsonb, '{"answer": 0, "explain": "The card warns that examiners do not award marks for describing what a method is — students must state the advantage for the business of using it."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:697a353c', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Key Fact — Internal vs External — Know the Data", "reading": "<p>From the BFF (Best Foot Forward) case study — always reference specific data when it is given:</p>\n<ul>\n<li>Internal recruitment cost: £500 vs External: £2,500 (£2,000 cheaper)</li>\n<li>Internal induction cost: £200 vs External: £1,500 (£1,300 cheaper)</li>\n<li>Total saving from internal: £3,300</li>\n<li>Days to fill the job: Internal 20 days vs External 60 days (3× faster)</li>\n</ul>\n<p>Using these numbers in analysis earns application marks.</p>", "question": "In the BFF case study data on this card, how much cheaper is internal recruitment cost compared to external?", "options": ["£1,300 cheaper", "£2,000 cheaper", "£500 cheaper", "£3,300 cheaper"]}'::jsonb, '{"answer": 1, "explain": "The card states internal recruitment cost is £500 versus external at £2,500 — a difference of £2,000."}'::jsonb),
('business:3-4-recruitment-and-selection:fib:574b9d7a', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'fib', 'fib', 4, '{"question": "Recruitment and _____ are very important to businesses. The _____ in a business make it successful or not. Recruiting new staff is _____. If good staff are not recruited by firms, money spent on the recruitment process is _____.", "blankOptions": {"B1": ["motivation", "selection", "earned", "products"], "B2": ["motivation", "planning", "riskier", "workers"], "B3": ["expensive", "earned", "harder", "CV"], "B4": ["interview", "inside", "cheaper", "wasted"]}}'::jsonb, '{"blanks": {"B1": "selection", "B2": "workers", "B3": "expensive", "B4": "wasted"}}'::jsonb),
('business:3-4-recruitment-and-selection:fib:a8ee35e1', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'fib', 'fib', 4, '{"question": "Internal recruitment is when a job vacancy is filled by someone _____ in the business. External recruitment is when someone from _____ the business is appointed. Internal recruitment is usually _____ and _____ than external recruitment.", "blankOptions": {"B1": ["already working", "workers", "letter", "person specification"], "B2": ["outside", "more expensive", "inside", "reference"], "B3": ["planning", "products", "application form", "cheaper"], "B4": ["quicker", "below", "recently leaving", "motivation"]}}'::jsonb, '{"blanks": {"B1": "already working", "B2": "outside", "B3": "cheaper", "B4": "quicker"}}'::jsonb),
('business:3-4-recruitment-and-selection:fib:0e1f225b', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'fib', 'fib', 4, '{"question": "A _____ lists the main duties and tasks of the worker. A _____ lists the qualities, qualifications and experience needed. Letters of application are good for showing a person''s _____ skills. A _____ is used at the final stage of selection and allows the interviewer to judge the candidate''s personality and communication.", "blankOptions": {"B1": ["outside", "job description", "advertising", "workers"], "B2": ["person specification", "recently leaving", "technical", "expensive"], "B3": ["simple", "invested", "communication", "scientific"], "B4": ["letter", "CV", "above", "interview"]}}'::jsonb, '{"blanks": {"B1": "job description", "B2": "person specification", "B3": "communication", "B4": "interview"}}'::jsonb),
('business:3-4-recruitment-and-selection:match:949b6c21', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Recruitment”?", "options": ["The process of choosing between applicants for a job", "A list of the main duties, tasks and responsibilities of a worker", "A list of the qualities, qualifications and knowledge a person should have to do a particular job", "The process of finding people to work in a new or established business"]}'::jsonb, '{"answer": 3, "explain": "“Recruitment” means: The process of finding people to work in a new or established business"}'::jsonb),
('business:3-4-recruitment-and-selection:match:f66da66a', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Selection”?", "options": ["A list of the main duties, tasks and responsibilities of a worker", "A list of the qualities, qualifications and knowledge a person should have to do a particular job", "When a business recruits skilled workers because it is short of them", "The process of choosing between applicants for a job"]}'::jsonb, '{"answer": 3, "explain": "“Selection” means: The process of choosing between applicants for a job"}'::jsonb),
('business:3-4-recruitment-and-selection:match:28162b5b', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Job description”?", "options": ["A list of the main duties, tasks and responsibilities of a worker", "A list of the qualities, qualifications and knowledge a person should have to do a particular job", "When a business recruits skilled workers because it is short of them", "Training to introduce a new worker to the business, place of work and fellow workers"]}'::jsonb, '{"answer": 0, "explain": "“Job description” means: A list of the main duties, tasks and responsibilities of a worker"}'::jsonb),
('business:3-4-recruitment-and-selection:match:84ae7d44', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Person specification”?", "options": ["When a business recruits skilled workers because it is short of them", "A list of the qualities, qualifications and knowledge a person should have to do a particular job", "Training to introduce a new worker to the business, place of work and fellow workers", "A document on which the applicant outlines their personal details, experience and skills"]}'::jsonb, '{"answer": 1, "explain": "“Person specification” means: A list of the qualities, qualifications and knowledge a person should have to do a particular job"}'::jsonb),
('business:3-4-recruitment-and-selection:match:a84c246c', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Skills gap”?", "options": ["Training to introduce a new worker to the business, place of work and fellow workers", "A document on which the applicant outlines their personal details, experience and skills", "A form specifying what information the business needs; all applicants fill in the same form", "When a business recruits skilled workers because it is short of them"]}'::jsonb, '{"answer": 3, "explain": "“Skills gap” means: When a business recruits skilled workers because it is short of them"}'::jsonb),
('business:3-4-recruitment-and-selection:match:2f217555', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Induction training”?", "options": ["A document on which the applicant outlines their personal details, experience and skills", "A form specifying what information the business needs; all applicants fill in the same form", "Training to introduce a new worker to the business, place of work and fellow workers", "The process of finding people to work in a new or established business"]}'::jsonb, '{"answer": 2, "explain": "“Induction training” means: Training to introduce a new worker to the business, place of work and fellow workers"}'::jsonb),
('business:3-4-recruitment-and-selection:match:a9044611', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “CV”?", "options": ["A form specifying what information the business needs; all applicants fill in the same form", "The process of finding people to work in a new or established business", "A document on which the applicant outlines their personal details, experience and skills", "The process of choosing between applicants for a job"]}'::jsonb, '{"answer": 2, "explain": "“CV” means: A document on which the applicant outlines their personal details, experience and skills"}'::jsonb),
('business:3-4-recruitment-and-selection:match:d79c7019', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Application form”?", "options": ["The process of finding people to work in a new or established business", "A form specifying what information the business needs; all applicants fill in the same form", "The process of choosing between applicants for a job", "A list of the main duties, tasks and responsibilities of a worker"]}'::jsonb, '{"answer": 1, "explain": "“Application form” means: A form specifying what information the business needs; all applicants fill in the same form"}'::jsonb),
('business:3-5-motivation-and-retention:exam:9ec15024', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q2", "question": "What is a financial method of motivation that a restaurant manager may use?", "options": ["An award scheme for the chefs to develop low cost meals", "Introduce profit sharing for the chefs", "Make staff pay for any glasses or plates they break", "Praise staff who suggest how the restaurant could save money"], "hint": "Think about which option involves a direct payment of money to workers.", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Introduce profit sharing for the chefs</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> An award scheme is a non-financial method of motivation — it involves recognition, not money.</li>\n  <li><strong>B — Correct:</strong> Profit sharing is a financial method — it involves paying workers a proportion of the business''s profits.</li>\n  <li><strong>C — Wrong:</strong> Making staff pay for breakages is a penalty/deduction, not a motivational method at all.</li>\n  <li><strong>D — Wrong:</strong> Praise is a non-financial method of motivation — it involves verbal/written recognition, not money.</li>\n</ul></div>", "modelAnswer": "B — Introduce profit sharing for the chefs."}'::jsonb),
('business:3-5-motivation-and-retention:exam:ab6871f7', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q3", "question": "What is a non-financial method of motivation that a manufacturer of handmade wooden toys could use?", "options": ["Giving production operatives a bonus for every 1000 toys made", "Increasing the rate of pay for workers in the dusty woodcutting shed", "Praising the workers who take the greatest care when painting the designs", "Providing free private medical insurance to all workers"], "hint": "Non-financial methods do NOT involve any payment of money or cash benefits. Which option involves recognition rather than pay?", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Praising the workers who take the greatest care when painting the designs</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> A bonus is a financial method — it is an additional cash payment for meeting a target.</li>\n  <li><strong>B — Wrong:</strong> Increasing the rate of pay is a financial method — it involves paying workers more money per hour.</li>\n  <li><strong>C — Correct:</strong> Praise is a non-financial method — it involves recognising and complimenting good work with no money exchanged.</li>\n  <li><strong>D — Wrong:</strong> Private medical insurance is a fringe benefit — a financial method, as it has a monetary value to the worker.</li>\n</ul></div>", "modelAnswer": "C — Praising the workers who take the greatest care when painting the designs."}'::jsonb),
('business:3-5-motivation-and-retention:exam:f4699117', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Employee retention:", "options": ["extends the working hours of employees", "leads to higher recruitment costs", "minimises time spent selecting new workers", "reduces discrimination in the workplace"], "hint": "Retention means workers STAY at a business. Think about what happens to recruitment if you don''t need to replace staff.", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — minimises time spent selecting new workers</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Retention refers to workers staying — it does not extend working hours.</li>\n  <li><strong>B — Wrong:</strong> High retention REDUCES recruitment costs, not increases them. This is the opposite of the correct answer.</li>\n  <li><strong>C — Correct:</strong> When workers stay (high retention), the business does not need to advertise and recruit as often, saving time spent on selection.</li>\n  <li><strong>D — Wrong:</strong> Retention has nothing to do with discrimination policies in the workplace.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Responses were evenly split across the three wrong options — candidates must know the precise definition of retention to avoid confusion with related HR terms.</p></div>", "modelAnswer": "C — minimises time spent selecting new workers."}'::jsonb),
('business:3-5-motivation-and-retention:exam:d00c7560', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q5", "question": "A supermarket chain is receiving an increasing number of complaints about the poor attitude of its sales assistants, especially when the stores are busy. What would help to deal with this problem?", "options": ["Employ fewer sales assistants at each of its stores", "Find ways to increase employee motivation at each of its stores", "Limit the number of customers that can enter each store at any one time", "Reduce the holiday entitlement of any employee that is rude to a customer"], "hint": "Poor attitude from staff is usually a symptom of something deeper. What business concept directly links to how hard and willingly workers perform?", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Find ways to increase employee motivation at each of its stores</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Fewer staff would make the pressure worse when stores are busy, increasing complaints rather than reducing them.</li>\n  <li><strong>B — Correct:</strong> Poor staff attitude is a symptom of low motivation. Improving motivation directly encourages staff to provide better customer service, especially under pressure.</li>\n  <li><strong>C — Wrong:</strong> Limiting customer numbers would reduce revenue and damage the business — it doesn''t address the root cause.</li>\n  <li><strong>D — Wrong:</strong> Reducing holiday entitlement is a punitive measure and would likely worsen morale and motivation, making the problem worse.</li>\n</ul></div>", "modelAnswer": "B — Find ways to increase employee motivation at each of its stores."}'::jsonb),
('business:3-5-motivation-and-retention:exam:83aba31c', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q6", "question": "A business has introduced a bonus scheme, based on production targets, to help motivate its staff. Which of the following statements would NOT be true?", "options": ["The bonus scheme is a form of performance-related pay", "The bonus scheme will increase business costs", "Unrealistic targets may lead to lower levels of motivation", "Workers who do not reach the target will have their basic pay reduced"], "hint": "Read the question carefully — it asks which statement is NOT true. A bonus is an addition to pay, not a reduction of it.", "starter": "The answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Workers who do not reach the target will have their basic pay reduced</h5>\n<ul>\n  <li><strong>A — True (not the answer):</strong> Bonuses are triggered by performance — they are a form of performance-related pay.</li>\n  <li><strong>B — True (not the answer):</strong> Paying bonuses adds to the business''s total wage costs.</li>\n  <li><strong>C — True (not the answer):</strong> If targets are unrealistically high, workers give up rather than try — the bonus demotivates instead of motivating.</li>\n  <li><strong>D — NOT True (correct answer):</strong> A bonus scheme does not reduce basic pay for those who miss targets. Basic pay remains the same — workers simply do not receive the additional bonus payment.</li>\n</ul></div>", "modelAnswer": "D — Workers who do not reach the target will have their basic pay reduced."}'::jsonb),
('business:3-5-motivation-and-retention:exam:46c2ba76', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Xaio and Zhou own a building firm that employs 50 workers. Xaio and Zhou are concerned about the costs of recruitment. They are constantly having to advertise for replacement workers. Which of the following would help Xaio and Zhou deal with this problem?", "options": ["Decrease the hourly rate paid to the workers", "Find ways to increase employee retention", "Give the workers fewer fringe benefits", "Obtain additional finance from the bank"], "hint": "The problem is that workers keep leaving. What is the business concept that means keeping workers in the business for longer?", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Find ways to increase employee retention</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Decreasing pay would make the problem worse — workers would be even more likely to leave for better-paid roles elsewhere.</li>\n  <li><strong>B — Correct:</strong> If workers stay longer (high retention), Xaio and Zhou would not need to constantly advertise for replacements — directly reducing recruitment costs.</li>\n  <li><strong>C — Wrong:</strong> Reducing fringe benefits would decrease motivation and increase turnover, making the recruitment problem worse.</li>\n  <li><strong>D — Wrong:</strong> Additional finance doesn''t address the root problem of workers leaving — it might help pay for more recruitment but doesn''t fix retention.</li>\n</ul></div>", "modelAnswer": "B — Find ways to increase employee retention."}'::jsonb),
('business:3-5-motivation-and-retention:exam:85fbcb40', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q10", "question": "A jet ski retailer with limited funds has a problem with the motivation levels of its 25 sales assistants. Which one of the following methods should the jet ski retailer use to improve the sales assistants'' motivation levels?", "options": ["Increase the sales assistants'' pay rate by £3 per hour", "Offer sales assistants a bonus of £500 for each jet ski sold", "Reduce the number of fringe benefits given to employees", "Set up a ''seller of the month'' award scheme"], "hint": "The key constraint is LIMITED FUNDS. Which option improves motivation without spending significant money?", "starter": "The answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Set up a ''seller of the month'' award scheme</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> A £3 per hour pay rise for 25 staff would be expensive — with limited funds, this may not be affordable.</li>\n  <li><strong>B — Wrong:</strong> A £500 bonus per jet ski sold could be very costly. Jet skis are expensive items — if sales are high, this could massively increase the wage bill.</li>\n  <li><strong>C — Wrong:</strong> Reducing fringe benefits would decrease motivation and morale — the opposite of what is needed.</li>\n  <li><strong>D — Correct:</strong> An award scheme is a non-financial method that costs very little but provides recognition and boosts morale — the ideal solution for a business with limited funds.</li>\n</ul></div>", "modelAnswer": "D — Set up a ''seller of the month'' award scheme."}'::jsonb),
('business:3-5-motivation-and-retention:exam:177ea7c3', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q14", "question": "Which one of the following is NOT a benefit to a business of improving employee retention?", "options": ["Cost saving", "Less time spent on recruitment", "Lower selling price", "Reduced need for training"], "hint": "Think carefully — retention means keeping workers longer. Three options are genuine benefits. One is completely unrelated to whether staff stay or leave.", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Lower selling price</h5>\n<ul>\n  <li><strong>A — Wrong (IS a benefit):</strong> Keeping existing staff avoids expensive recruitment and training costs — a direct cost saving.</li>\n  <li><strong>B — Wrong (IS a benefit):</strong> If workers stay, there is less need to recruit replacements — saving management time on selection.</li>\n  <li><strong>C — Correct (NOT a benefit):</strong> The selling price of products is a marketing/pricing decision — it is completely unrelated to employee retention.</li>\n  <li><strong>D — Wrong (IS a benefit):</strong> Retained workers already know the job and don''t need retraining — reducing training costs.</li>\n</ul></div>", "modelAnswer": "C — Lower selling price."}'::jsonb),
('business:3-5-motivation-and-retention:mcq:e2fd1b0f', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "A worker is paid £8 per hour for working a 35-hour week. On top of this, the worker is paid a bonus of 10% of their wage for the week. How much did the worker earn in total?", "options": ["£280", "£420", "£308", "£282.80"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — £308. Step 1: £8 × 35 = £280 basic wage. Step 2: 10% bonus = £28. Step 3: £280 + £28 = £308. Do not confuse the bonus with overtime — a 10% bonus is added on top of the full week''s pay."}'::jsonb),
('business:3-5-motivation-and-retention:mcq:dfa35a85', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Which of the following is a financial method of motivating workers?", "options": ["A good working environment", "Award scheme", "Praise", "Profit sharing"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Profit sharing. Award schemes, praise, and a good working environment are all non-financial methods. Profit sharing directly involves paying workers a share of the business''s money, making it a financial method."}'::jsonb),
('business:3-5-motivation-and-retention:mcq:7df1b821', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of a method of motivating workers?", "options": ["Increased retention of workers", "Increased productivity of staff", "An increase in some of the costs of the business", "A reduction in absenteeism"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: A — an increase in costs. Options B, C and D are all benefits of motivation. Increased costs (e.g. bonus payments, pay rises, fringe benefits) is the key disadvantage to the business of using financial motivation methods."}'::jsonb),
('business:3-5-motivation-and-retention:mcq:83875fa6', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Jowill, an employer, raises the pay of her eight employees by £1.50 per hour. They work 35 hours each week. After the increase, Jowill''s revenue increased by £680 per week. Which statement is true?", "options": ["Jowill''s costs rose by £680 per week.", "Jowill''s profit rose by £260 per year.", "The increase in Jowill''s revenue per week exceeded her increase in costs by £260.", "Jowill''s revenue rose by £420 per week."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Cost increase = 8 workers × £1.50 × 35 hours = £420 per week. Revenue increase = £680. £680 − £420 = £260 extra profit per week. Option A is wrong (costs rose by £420, not £680). Option B confuses weekly gain with annual. Option D is wrong (revenue rose by £680, not £420)."}'::jsonb),
('business:3-5-motivation-and-retention:mcq:9ec15024', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "What is a financial method of motivation that a restaurant manager may use?", "options": ["Make staff pay for any glasses or plates they break", "An award scheme for the chefs to develop low cost meals", "Introduce profit sharing for the chefs", "Praise staff who suggest how the restaurant could save money"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: B — profit sharing. This involves giving workers a share of the business''s profits, which is a direct financial payment. A is an award scheme (non-financial). C is a penalty, not motivation. D is praise (non-financial)."}'::jsonb),
('business:3-5-motivation-and-retention:mcq:ab6871f7', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "What is a non-financial method of motivation that a manufacturer of handmade wooden toys could use?", "options": ["Giving production operatives a bonus for every 1000 toys made", "Increasing the rate of pay for workers in the dusty woodcutting shed", "Praising the workers who take the greatest care when painting the designs", "Providing free private medical insurance to all workers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — praise. This involves recognising good work verbally or formally, with no money exchanged. Options A and B involve payments (financial). Option D is a fringe benefit (financial method)."}'::jsonb),
('business:3-5-motivation-and-retention:mcq:b51205e7', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Employee retention...", "options": ["extends the working hours of employees", "leads to higher recruitment costs", "minimises time spent selecting new workers", "reduces discrimination in the workplace"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. When workers stay with a business (high retention), there is less need to recruit replacements, so less time is spent on selection processes. Option B is the opposite — high retention REDUCES recruitment costs. Options A and D are not linked to the definition of retention."}'::jsonb),
('business:3-5-motivation-and-retention:mcq:c2f6a34b', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "A business has introduced a bonus scheme based on production targets. Which of the following statements would NOT be true?", "options": ["Workers who do not reach the target will have their basic pay reduced", "Unrealistic targets may lead to lower levels of motivation", "The bonus scheme will increase business costs", "The bonus scheme is a form of performance-related pay"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: D. A bonus scheme adds extra pay for reaching targets — it does NOT reduce basic pay for those who miss targets. A is true (bonuses are performance-related pay). B is true (bonuses add to costs). C is true (unrealistic targets can demotivate)."}'::jsonb)
